    if (orderRepo.existsByOrderId(orderId)) {
        log.info("Order {} already exists — skipping duplicate event", orderId);
        return; // idempotent — safe to call multiple times
    }
    orderRepo.save(new Order(orderId, "CREATED"));
}
```

