    SQLStatementCountValidator.reset();

    orderService.getOrdersWithItems(); // the method under test

    assertSelectCount(1);  // fails if more than 1 SELECT was executed
    // assertSelectCount(3); // allow exactly 3 (for @BatchSize case)
}
```

