## Step 4 — Delivery status tracking

```java
@Service
@RequiredArgsConstructor
public class DeliveryStatusService {

    private final RedisTemplate<String, String> redis;
    private final DeliveryStatusRepository statusRepo;  // PostgreSQL

    public void markDelivered(UUID notifId, String channel, String externalId) {
        // Redis for fast lookups (24h TTL)
        String key = "notif:status:" + notifId + ":" + channel;
        redis.opsForValue().set(key, "DELIVERED:" + externalId, 24, TimeUnit.HOURS);

        // PostgreSQL for permanent audit trail
        statusRepo.save(DeliveryStatus.builder()
            .notificationId(notifId)
            .channel(channel)
            .status(DeliveryStatus.Status.DELIVERED)
            .externalId(externalId)
            .deliveredAt(Instant.now())
            .build());
    }

    public String getStatus(UUID notifId, String channel) {
        // Fast path: Redis
        String key = "notif:status:" + notifId + ":" + channel;
        String cached = redis.opsForValue().get(key);
        if (cached != null) return cached;

        // Slow path: PostgreSQL (for old notifications past Redis TTL)
        return statusRepo.findByNotificationIdAndChannel(notifId, channel)
            .map(s -> s.getStatus().name())
            .orElse("UNKNOWN");
    }
}
```

