## Step 4 — Spring Security filter validates version

```java
@Component
@RequiredArgsConstructor
public class JwtAuthFilter extends OncePerRequestFilter {

    private final JwtService jwtService;
    private final UserRepository userRepo;

    @Override
    protected void doFilterInternal(HttpServletRequest req,
            HttpServletResponse res, FilterChain chain)
            throws ServletException, IOException {

        String authHeader = req.getHeader("Authorization");
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            chain.doFilter(req, res); return;
        }

        String token = authHeader.substring(7);
        Claims claims = jwtService.validateToken(token, false);

        Long userId = Long.valueOf(claims.getSubject());
        Integer tokenVersion = claims.get("version", Integer.class);

        // Version check — catches password changes without DB blacklist overhead
        User user = userRepo.findById(userId).orElseThrow();
        if (!user.getTokenVersion().equals(tokenVersion)) {
            res.setStatus(HttpStatus.UNAUTHORIZED.value());
            res.getWriter().write("{\"error\": \"Token invalidated — please log in again\"}");
            return;
        }

        UsernamePasswordAuthenticationToken auth =
            new UsernamePasswordAuthenticationToken(user, null, user.getAuthorities());
        SecurityContextHolder.getContext().setAuthentication(auth);
        chain.doFilter(req, res);
    }
}
```

