## Step 4: Search repository and queries

```java
@Component
@RequiredArgsConstructor
public class ProductSearchService {

    private final ElasticsearchOperations esOps;

    public SearchHits<ProductDocument> search(ProductSearchRequest request) {

        BoolQuery.Builder queryBuilder = QueryBuilders.bool();

        // Full-text search on name and description
        // name gets 3x boost — matching in title is more important
        if (StringUtils.hasText(request.getKeyword())) {
            queryBuilder.must(QueryBuilders.multiMatch(mm -> mm
                .query(request.getKeyword())
                .fields("name^3", "description")  // ^3 = 3x boost for name
                .type(TextQueryType.BestFields)
                .fuzziness("AUTO")  // allows 1-2 character typos
            ));
        }

        // Exact filters (Keyword fields)
        if (request.getBrand() != null) {
            queryBuilder.filter(QueryBuilders.term(t -> t.field("brand").value(request.getBrand())));
        }
        if (request.getCategory() != null) {
            queryBuilder.filter(QueryBuilders.term(t -> t.field("category").value(request.getCategory())));
        }
        if (Boolean.TRUE.equals(request.getInStockOnly())) {
            queryBuilder.filter(QueryBuilders.term(t -> t.field("inStock").value(true)));
        }

        // Price range filter
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            queryBuilder.filter(QueryBuilders.range(r -> {
                r.field("price");
                if (request.getMinPrice() != null) r.gte(JsonData.of(request.getMinPrice()));
                if (request.getMaxPrice() != null) r.lte(JsonData.of(request.getMaxPrice()));
                return r;
            }));
        }

        NativeQuery query = NativeQuery.builder()
            .withQuery(queryBuilder.build()._toQuery())
            .withPageable(request.getPageable())
            .withSort(Sort.by("_score").descending())
            .build();

        return esOps.search(query, ProductDocument.class);
    }
}
```

