        doInvoicing();
        // Record last successful run
        redis.opsForValue().set("job:billing:last-success",
            Instant.now().toString(), 25, TimeUnit.HOURS);
        billingJobSuccessCounter.increment();  // Prometheus counter
    } catch (Exception e) {
        log.error("Billing job failed", e);
