```java
@Service
@RequiredArgsConstructor
public class CheckoutService {

    private final Unleash unleash;
    private final OldCheckoutProcessor oldCheckout;
    private final NewCheckoutProcessor newCheckout;

    public CheckoutResult processCheckout(CheckoutRequest request, Long userId) {
        // Check feature flag — is this user in the new checkout group?
        UnleashContext context = UnleashContext.builder()
            .userId(userId.toString())
            .addProperty("country", request.getCountry())
            .build();

        boolean useNewCheckout = unleash.isEnabled("new-checkout-flow", context);

        if (useNewCheckout) {
            log.info("[new-checkout] Processing for user {}", userId);
            return newCheckout.process(request);
        } else {
            return oldCheckout.process(request);
        }
    }
}
```

